import{_ as t,a as e,b as d}from"./chunks/配置渠道内容.HzNkdrom.js";import{_ as s,o as n,c as i,a2 as o}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"Додавання каналу GitLab Packages","description":"","frontmatter":{},"headers":[],"relativePath":"uk-UA/upload/gitlab-packages.md","filePath":"uk-UA/upload/gitlab-packages.md","lastUpdated":1781962217000}'),r={name:"uk-UA/upload/gitlab-packages.md"};function l(c,a,p,b,h,g){return n(),i("div",null,[...a[0]||(a[0]=[o('<h1 id="додавання-каналу-gitlab-packages" tabindex="-1">Додавання каналу GitLab Packages <a class="header-anchor" href="#додавання-каналу-gitlab-packages" aria-label="Permalink to &quot;Додавання каналу GitLab Packages&quot;">​</a></h1><h2 id="що-підготувати-заздалегідь" tabindex="-1">Що підготувати заздалегідь <a class="header-anchor" href="#що-підготувати-заздалегідь" aria-label="Permalink to &quot;Що підготувати заздалегідь&quot;">​</a></h2><p>Потрібні лише три речі:</p><table tabindex="0"><thead><tr><th>Потрібно</th><th>Навіщо це потрібно</th></tr></thead><tbody><tr><td>Обліковий запис GitLab</td><td>Для створення access token і володіння проєктом.</td></tr><tr><td>GitLab Personal Access Token</td><td>ImgBed використовує його для доступу до GitLab API, створення проєктів і завантаження файлів у Generic Packages.</td></tr><tr><td>Назва проєкту</td><td>Можна ввести тільки назву проєкту, наприклад <code>imgbed</code>.</td></tr></tbody></table><h2 id="налаштування" tabindex="-1">Налаштування <a class="header-anchor" href="#налаштування" aria-label="Permalink to &quot;Налаштування&quot;">​</a></h2><h3 id="крок-1-увіидіть-у-gitlab-і-створіть-access-token" tabindex="-1">Крок 1. Увійдіть у GitLab і створіть Access Token <a class="header-anchor" href="#крок-1-увіидіть-у-gitlab-і-створіть-access-token" aria-label="Permalink to &quot;Крок 1. Увійдіть у GitLab і створіть Access Token&quot;">​</a></h3><ol><li>Увійдіть у GitLab.</li><li>Натисніть свій аватар у правому верхньому куті й відкрийте <code>Preferences</code>.</li><li>У лівій бічній панелі відкрийте <code>Access Tokens</code>.</li><li>Дайте token зрозумілу назву.</li><li>Виберіть дату закінчення дії відповідно до вашого підходу до обслуговування.</li><li>Виберіть scope <code>api</code>.</li><li>Одразу після створення скопіюйте й збережіть token.</li></ol><p><img src="'+t+'" alt="Створення legacy token" loading="lazy"></p><p><img src="'+e+'" alt="Вибір прав token" loading="lazy"></p><h2 id="крок-2-заповніть-канал-gitlab-packages-в-imgbed" tabindex="-1">Крок 2. Заповніть канал GitLab Packages в ImgBed <a class="header-anchor" href="#крок-2-заповніть-канал-gitlab-packages-в-imgbed" aria-label="Permalink to &quot;Крок 2. Заповніть канал GitLab Packages в ImgBed&quot;">​</a></h2><p>Після вибору <code>GitLab Packages</code> у налаштуваннях завантаження заповніть поля так:</p><table tabindex="0"><thead><tr><th>Поле в інтерфейсі</th><th>Що ввести</th></tr></thead><tbody><tr><td>Channel name</td><td>Назва на ваш вибір, наприклад <code>GitLabPrimary</code>.</td></tr><tr><td>Access Token</td><td>GitLab Personal Access Token, який ви щойно створили.</td></tr><tr><td>Project name</td><td>Або коротка назва проєкту, наприклад <code>imgbed</code>, або повний шлях на кшталт <code>username/imgbed</code>.</td></tr><tr><td>Private repository</td><td>Увімкніть або вимкніть відповідно до ваших потреб.</td></tr><tr><td>Remark</td><td>Необов&#39;язково, наприклад <code>Primary upload channel</code>.</td></tr></tbody></table><p><img src="'+d+`" alt="Налаштування каналу" loading="lazy"></p><h2 id="крок-3-збережіть-канал" tabindex="-1">Крок 3. Збережіть канал <a class="header-anchor" href="#крок-3-збережіть-канал" aria-label="Permalink to &quot;Крок 3. Збережіть канал&quot;">​</a></h2><p>Після заповнення полів натисніть Save.</p><p>Система сама обробить такі деталі:</p><table tabindex="0"><thead><tr><th>Поведінка системи</th><th>Опис</th></tr></thead><tbody><tr><td>Коротка назва проєкту</td><td>ImgBed визначає поточний обліковий запис GitLab і розгортає значення до повного шляху проєкту.</td></tr><tr><td>Повний шлях проєкту</td><td>ImgBed використовує шлях <code>username/project</code> саме в тому вигляді, у якому його введено.</td></tr><tr><td>Перевірка проєкту</td><td>Якщо використовується шлях поточного особистого акаунта, ImgBed автоматично створює проєкт, коли його ще немає. Якщо повний шлях введено вручну, ImgBed використовує його напряму.</td></tr><tr><td>Публічний або приватний стан</td><td>Видимість проєкту синхронізується відповідно до поточного перемикача.</td></tr></tbody></table><h2 id="короткии-чекліст" tabindex="-1">Короткий чекліст <a class="header-anchor" href="#короткии-чекліст" aria-label="Permalink to &quot;Короткий чекліст&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Увійти в GitLab</span></span>
<span class="line"><span>-&gt; Створити Access Token</span></span>
<span class="line"><span>-&gt; Вибрати тільки scope api</span></span>
<span class="line"><span>-&gt; Повернутися до ImgBed і ввести token та назву проєкту</span></span>
<span class="line"><span>-&gt; Зберегти</span></span>
<span class="line"><span>-&gt; Якщо введено тільки назву проєкту, ImgBed автоматично додасть поточний username</span></span>
<span class="line"><span>-&gt; Якщо введено username/project, ImgBed використає це як є</span></span>
<span class="line"><span>-&gt; Завантажити тестове зображення</span></span></code></pre></div>`,19)])])}const _=s(r,[["render",l]]);export{u as __pageData,_ as default};
